arguments.newString:
bool myConstantPropagation(Function &Foo) {
  if (Foo.empty())
    return false;

  bool Changed = false;

  for (BasicBlock &BB : Foo) {
    for (auto It = BB.begin(), E = BB.end(); It != E;) {
      Instruction *I = &*It++;

      BinaryOperator *BO = dyn_cast<BinaryOperator>(I);
      if (!BO)
        continue;

      ConstantInt *LHS = dyn_cast<ConstantInt>(BO->getOperand(0));
      ConstantInt *RHS = dyn_cast<ConstantInt>(BO->getOperand(1));
      if (!LHS || !RHS)
        continue;

      const APInt &L = LHS->getValue();
      const APInt &R = RHS->getValue();
      std::optional<APInt> Result;

      switch (BO->getOpcode()) {
      case Instruction::Add:
        Result = L + R;
        break;
      case Instruction::Sub:
        Result = L - R;
        break;
      case Instruction::Mul:
        Result = L * R;
        break;
      case Instruction::SDiv:
        if (R.isZero())
          continue;
        Result = L.sdiv(R);
        break;
      case Instruction::UDiv:
        if (R.isZero())
          continue;
        Result = L.udiv(R);
        break;
      case Instruction::Shl:
      case Instruction::LShr:
      case Instruction::AShr: {
        unsigned ShiftAmt = static_cast<unsigned>(R.getLimitedValue(UINT_MAX));
        if (ShiftAmt >= L.getBitWidth())
          continue;
        if (BO->getOpcode() == Instruction::Shl)
          Result = L.shl(ShiftAmt);
        else if (BO->getOpcode() == Instruction::LShr)
          Result = L.lshr(ShiftAmt);
        else
          Result = L.ashr(ShiftAmt);
        break;
      }
      case Instruction::And:
        Result = L & R;
        break;
      case Instruction::Or:
        Result = L | R;
        break;
      case Instruction::Xor:
        Result = L ^ R;
        break;
      default:
        continue;
      }

      if (!Result)
        continue;

      Constant *NewConst = ConstantInt::get(BO->getType(), *Result);
      BO->replaceAllUsesWith(NewConst);
      BO->eraseFromParent();
      Changed = true;
    }
  }

  return Changed;
}
